  if (item.onEquifax === true) bureaus.push('equifax');
  else if (item.onEquifax === undefined && (!item.bureau || item.bureau === 'combined' || item.bureau === 'equifax')) {
    bureaus.push('equifax');
  }

  return bureaus;
}

