  if (!match) return undefined;

  const value = match[1];
  if (/^\d{1,2}[\/\-]\d{4}$/.test(value)) {
    const [month, year] = value.split(/[\/\-]/);
    return new Date(Date.UTC(Number(year), Number(month) - 1, 1));
  }

  return parseDate(value);
}

